INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (1, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "あたしだって\nやるときはやるよ！", 0, 0.0, 24, 102601, 24001, 1, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (1, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "ふぅ…\nこれであたしの仕事は\n終わりだね", 1, 0.0, 24, 102601, 24002, 1, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (1, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "終わった終わった\n一人でもなんとか\nなるもんだね", 2, 0.0, 24, 102601, 24003, 1, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (2, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "やったね！\nこれでようやく\nサボれるよ…", 3, 0.0, 24, 102601, 24004, 2, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (1, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 4, 0.0, 24, 102601, 24005, 1, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (2, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 5, 0.0, 24, 102601, 24006, 2, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (2, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "あたしも意外と\nやるもんでしょ？", 6, 0.0, 24, 102601, 24007, 2, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (4, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "疲れた…\nねずみの逃げ足\n速すぎるよ…", 7, 0.0, 24, 102601, 24008, 4, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (4, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "このままじゃ\nまっひ～に\n叱られちゃうよ", 8, 0.0, 24, 102601, 24009, 4, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (4, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "まじめに\nやったんだけどな…\n悔しいな～", 9, 0.0, 24, 102601, 24010, 4, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (4, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "やられた…\nねずみって意外と\nてごわいね", 10, 0.0, 24, 102601, 24011, 4, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (4, 0.0, 10040, "リン", 0.0, "2030/12/17 14:59:59", "おのれ～\nあたしのチーズを\n盗みやがって～！", 11, 0.0, 24, 102601, 24012, 4, "2020/04/30 12:00:00");
INSERT INTO `v1_d1f7812692e05b315d378e41d9110c0334f02f98680f039ae0a256da44799ad7` VALUES (1, 0.0, 10040, "リン", 1.81, "2030/12/17 14:59:59", "疲れた…\nけど、次こそは\n守り抜くよ…", 12, 0.0, 24, 102601, 24013, 4, "2020/04/30 12:00:00");
